        // Apply metal and shine
        metal(0.6304962928840792 * size);
        shine(0.6210181878056416);

        // Render the shapes
        cylinder(size * 0.9446738625954518 - pointerDown * 0.05 / 4, size * 0.9446738625954518 - pointerDown * 0.05);
sphere(size * 0.7023682612074287 - pointerDown * 0.05 / 2);

